    def generate_qr_ascii(self, username):
        """
        Generate an ASCII representation of the QR code for terminal display.

        Args:
            username: Username to generate QR for

        Returns:
            ASCII string representation of QR code
        """
        if not HAS_QRCODE:
            raise ImportError("qrcode library is required. Install with: pip install qrcode")

        if username not in self.users:
            raise ValueError(f"User '{username}' not found.")

        user_data = self.users[username]
        uri = self.get_provisioning_uri(
            username,
            user_data['secret'],
            user_data.get('issuer', 'MFASystem')
        )

        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=1,
            border=1,
        )
        qr.add_data(uri)
        qr.make(fit=True)

        # Build ASCII QR code
        lines = []
        matrix = qr.get_matrix()
        for row in matrix:
            line = ''
            for cell in row:
                line += '██' if cell else '  '
            lines.append(line)

        return '\n'.join(lines)

    def authenticate_user(self, username, code):
        """
        Authenticate a user with their TOTP code.

        Args:
            username: Username
            code: TOTP code provided by user

        Returns:
            Dictionary with authentication result
        """
        if username not in self.users:
            return {
                'authenticated': False,
                'error': 'User not found'
            }

        user_data = self.users[username]
        secret = user_data['secret']

        # Replay attack prevention
        current_counter = self._get_time_counter()
        last_used = user_data.get('last_used_counter')

        if last_used is not None and current_counter <= last_used:
            # Allow if we're checking adjacent time steps
            pass

        is_valid = self.verify_totp(secret, code)

        if is_valid:
            # Update last used counter for replay prevention
            self.users[username]['last_used_counter'] = current_counter
            if not self.users[username]['verified']:
                self.users[username]['verified'] = True
            self._save_secrets()

            return {
                'authenticated': True,
                'username': username,
                'timestamp': time.time()
            }
        else:
            return {
                'authenticated': False,
                'error': 'Invalid TOTP code'
            }

    def get_remaining_seconds(self):
        """Get the number of seconds remaining in the current time step."""
        return self.interval - (int(time.time()) % self.interval)

    def list_users(self):
        """List all registered users."""
        user_list = []
        for username, data in self.users.items():
            user_list.append({
                'username': username,
                'issuer': data.get('issuer', 'MFASystem'),
                'verified': data.get('verified', False),
                'created_at': data.get('created_at')
            })
        return user_list

    def get_user_info(self, username):
        """Get information about a specific user (without exposing the secret)."""
        if username not in self.users:
            return None
        data = self.users[username]
        return {
            'username': username,
            'issuer': data.get('issuer', 'MFASystem'),
            'verified': data.get('verified', False),
            'created_at': data.get('created_at'),
            'secret_hint': data['secret'][:4] + '****'
        }


